insert into recipes (
  code,
  name,
  category,
  status,
  prep_time_min,
  cook_time_min,
  cost_level,
  image_url,
  source_url,
  blw_summary,
  separation_moment,
  notes
) values
('RF001', 'Arroz de feijao com cenoura e couve', 'Vegetariana', 'por_testar', 10, 30, 'baixo', 'https://source.unsplash.com/1200x800/?rice,beans,stew', 'https://www.nhs.uk/baby/weaning-and-feeding/babys-first-solid-foods/', 'Arroz muito macio e humido; feijao bem cozido e esmagado; cenoura em palitos macios ou esmagada; sem sal.', 'Retirar a porcao da bebe antes de adicionar sal, caldo, enchidos ou picante.', '1. Lavar o arroz e cortar a cenoura em palitos grossos.\n2. Cozer a cenoura e a couve ate ficarem macias.\n3. Juntar arroz, feijao cozido e agua suficiente para ficar malandrinho.\n4. Cozinhar ate o arroz abrir e o caldo ficar cremoso.\n5. Retirar a porcao BLW sem sal, esmagando parte do feijao.\n6. Temperar a panela dos adultos com azeite e ervas suaves no fim.'),
('RF002', 'Massa com molho de abobora e lentilhas', 'Vegan', 'por_testar', 10, 25, 'baixo', 'https://source.unsplash.com/1200x800/?pumpkin,pasta,lentils', 'https://www.nhs.uk/baby/weaning-and-feeding/babys-first-solid-foods/', 'Massa bem cozida; lentilhas vermelhas desfeitas em molho espesso; abobora muito macia; sem sal.', 'Separar a porcao da bebe depois de envolver a massa no molho sem sal.', '1. Cozer a abobora em cubos com lentilhas vermelhas e tomate sem sal.\n2. Triturar parcialmente para obter um molho espesso.\n3. Cozer a massa mais tempo do que al dente.\n4. Envolver a massa no molho e ajustar com agua da cozedura.\n5. Retirar a porcao BLW e cortar a massa se necessario.\n6. Temperar os adultos com azeite, pimenta ou ervas no prato.'),
('RF003', 'Bacalhau espiritual adaptado sem leite', 'Peixe', 'por_testar', 20, 30, 'medio', 'https://source.unsplash.com/1200x800/?cod,potato,casserole', 'https://www.nhs.uk/baby/weaning-and-feeding/babys-first-solid-foods/', 'Bacalhau muito bem demolhado, sem espinhas e em pequena porcao; batata e cenoura macias; bebida vegetal sem acucar.', 'Retirar a porcao da bebe antes de salgar, gratinar ou acrescentar temperos fortes.', '1. Confirmar que o bacalhau esta bem demolhado e sem espinhas.\n2. Cozer batata e cenoura ate ficarem muito macias.\n3. Lascar o bacalhau e envolver com legumes esmagados e bebida vegetal sem acucar.\n4. Cozinhar ate ficar cremoso, sem adicionar sal.\n5. Separar a porcao BLW e ajustar textura com batata esmagada.\n6. Levar o restante ao forno para os adultos se desejado.'),
('RF004', 'Gratinado de batata, brocolos e grao', 'Vegan', 'por_testar', 15, 30, 'baixo', 'https://source.unsplash.com/1200x800/?potato,broccoli,chickpeas', 'https://www.nhs.uk/baby/weaning-and-feeding/babys-first-solid-foods/', 'Batata macia; grao esmagado ou triturado; brocolos muito cozidos em floretes grandes; sem sal.', 'Separar antes de salgar e antes de gratinar com toppings dos adultos.', '1. Cozer batata e brocolos ate ficarem bem macios.\n2. Esmagar o grao com azeite e um pouco de agua quente.\n3. Montar uma travessa com batata, grao e brocolos.\n4. Separar uma porcao sem sal para a bebe.\n5. Gratinar o restante ate dourar ligeiramente.\n6. Servir a bebe com floretes grandes e batata esmagada.'),
('RF005', 'Almondegas de lentilhas com arroz de tomate', 'Vegan', 'por_testar', 25, 30, 'baixo', 'https://source.unsplash.com/1200x800/?lentil,meatballs,tomato,rice', 'https://www.nhs.uk/baby/weaning-and-feeding/babys-first-solid-foods/', 'Almondegas grandes, moles e achatadas; lentilhas muito cozidas; arroz de tomate humido; sem sal.', 'Separar a massa das almondegas e parte do arroz antes de salgar o molho dos adultos.', '1. Cozer lentilhas ate ficarem bem macias e escorrer.\n2. Esmagar com aveia e cenoura ralada cozinhada ate formar uma massa moldavel.\n3. Formar bolas grandes ou discos macios e levar ao forno.\n4. Fazer arroz de tomate sem sal, deixando-o humido.\n5. Retirar a porcao BLW antes de temperos fortes.\n6. Servir as almondegas partidas ao meio para verificar textura.'),
('RF006', 'Sopa rica de grao, cenoura e batata-doce', 'Vegan', 'por_testar', 10, 30, 'baixo', 'https://source.unsplash.com/1200x800/?chickpea,soup,sweet,potato', 'https://www.nhs.uk/baby/weaning-and-feeding/babys-first-solid-foods/', 'Legumes muito cozidos; grao triturado ou esmagado; sopa espessa para aderir a colher pre-carregada; sem sal.', 'Retirar a porcao da bebe antes de salgar ou usar caldo.', '1. Cortar cenoura, batata-doce e tomate.\n2. Cozer com grao e couve ate tudo ficar muito macio.\n3. Triturar parcialmente para manter textura espessa.\n4. Retirar a porcao BLW sem sal.\n5. Ajustar com agua se estiver demasiado grossa.\n6. Temperar a sopa dos adultos no fim.'),
('RF007', 'Massa espiral com ervilhas e molho de tomate suave', 'Vegan', 'por_testar', 10, 20, 'baixo', 'https://source.unsplash.com/1200x800/?pasta,peas,tomato', 'https://www.nhs.uk/baby/weaning-and-feeding/babys-first-solid-foods/', 'Massa bem cozida; ervilhas esmagadas; molho de tomate sem sal e pouco acido.', 'Separar depois de envolver em molho sem sal.', '1. Cozer a massa ate ficar bem macia.\n2. Cozinhar tomate triturado com cenoura ralada ate suavizar.\n3. Cozer ervilhas e esmagar parte delas.\n4. Envolver massa, molho e ervilhas.\n5. Retirar a porcao BLW e cortar espirais grandes se preciso.\n6. Ajustar os adultos com ervas, azeite e sal no prato.'),
('RF008', 'Feijoada vegetariana suave com arroz', 'Vegan', 'por_testar', 15, 35, 'baixo', 'https://source.unsplash.com/1200x800/?white,beans,rice,stew', 'https://www.nhs.uk/baby/weaning-and-feeding/babys-first-solid-foods/', 'Feijao branco muito macio e esmagado; couve bem cozida; arroz humido; sem sal.', 'Separar antes de salgar e antes de qualquer enchido vegetal ou picante dos adultos.', '1. Cozer cenoura e couve lombarda ate ficarem macias.\n2. Juntar feijao branco cozido e tomate, sem sal.\n3. Cozinhar ate o caldo engrossar.\n4. Fazer arroz simples e humido.\n5. Retirar a porcao BLW, esmagando feijao e cenoura.\n6. Temperar a feijoada dos adultos no fim.'),
('RF009', 'Empadao de lentilhas e batata', 'Vegetariana', 'por_testar', 20, 35, 'baixo', 'https://source.unsplash.com/1200x800/?lentil,potato,pie', 'https://www.nhs.uk/baby/weaning-and-feeding/babys-first-solid-foods/', 'Pure de batata macio sem sal; lentilhas bem cozidas; recheio humido e facil de esmagar.', 'Separar antes de salgar o recheio e antes de gratinar.', '1. Cozer batata e esmagar com azeite e agua da cozedura.\n2. Cozinhar lentilhas com cenoura e tomate sem sal.\n3. Deixar o recheio humido e macio.\n4. Montar empadao com pure por cima.\n5. Separar uma porcao pequena antes de gratinar.\n6. Gratinar o restante para os adultos.'),
('RF010', 'Arroz de pescada com cenoura e ervilhas', 'Peixe', 'por_testar', 10, 30, 'medio', 'https://source.unsplash.com/1200x800/?hake,rice,peas', 'https://www.nhs.uk/baby/weaning-and-feeding/babys-first-solid-foods/', 'Pescada sem espinhas; arroz malandrinho; cenoura macia; ervilhas esmagadas; sem sal.', 'Retirar a porcao da bebe antes de salgar a panela dos adultos.', '1. Cozer a pescada e rever cuidadosamente todas as espinhas.\n2. Fazer base com arroz, cenoura e bastante agua.\n3. Juntar pescada lascada e ervilhas.\n4. Cozinhar ate o arroz ficar muito macio.\n5. Retirar porcao BLW sem sal e esmagar ervilhas.\n6. Finalizar a dose dos adultos com azeite e ervas.'),
('RF011', 'Tortilha de batata, ervilhas e cenoura no forno', 'Vegetariana', 'por_testar', 15, 30, 'baixo', 'https://source.unsplash.com/1200x800/?potato,omelette,peas', 'https://www.nhs.uk/baby/weaning-and-feeding/babys-first-solid-foods/', 'Ovo totalmente cozinhado; tiras grossas e macias; batata e cenoura previamente cozidas; sem sal.', 'Separar a mistura da bebe antes de temperar a dos adultos.', '1. Cozer batata, cenoura e ervilhas ate ficarem macias.\n2. Bater ovos sem sal.\n3. Misturar legumes e ovos numa forma pequena.\n4. Levar ao forno ate o centro ficar totalmente cozinhado.\n5. Cortar em tiras grossas para BLW.\n6. Temperar apenas as fatias dos adultos.'),
('RF012', 'Estufado de grao com abobora e couscous', 'Vegan', 'por_testar', 10, 30, 'baixo', 'https://source.unsplash.com/1200x800/?chickpea,pumpkin,couscous', 'https://www.nhs.uk/baby/weaning-and-feeding/babys-first-solid-foods/', 'Grao esmagado; abobora e brocolos muito macios; couscous bem hidratado e humido; sem sal.', 'Retirar o estufado da bebe antes de salgar e servir couscous simples.', '1. Cozinhar abobora e brocolos com grao e tomate sem sal.\n2. Deixar a abobora desfazer parcialmente no molho.\n3. Hidratar couscous com agua quente sem sal e azeite.\n4. Esmagar parte do grao.\n5. Separar a porcao BLW com bastante molho.\n6. Temperar o restante com especiarias suaves no prato.'),
('RF013', 'Massa de forno com lentilhas vermelhas e couve-flor', 'Vegan', 'por_testar', 15, 35, 'baixo', 'https://source.unsplash.com/1200x800/?baked,pasta,cauliflower,lentils', 'https://www.nhs.uk/baby/weaning-and-feeding/babys-first-solid-foods/', 'Massa bem cozida; lentilhas desfeitas em molho; couve-flor muito macia; sem sal.', 'Separar antes de salgar e antes de gratinar a parte dos adultos.', '1. Cozer massa e couve-flor ate ficarem macias.\n2. Cozinhar lentilhas vermelhas com tomate sem sal ate virarem molho.\n3. Envolver tudo numa travessa.\n4. Retirar porcao BLW antes de qualquer sal ou topping.\n5. Levar o restante ao forno para ganhar textura.\n6. Servir a bebe com molho extra para ficar humido.'),
('RF014', 'Hamburgueres de feijao preto e batata-doce', 'Vegan', 'por_testar', 20, 30, 'baixo', 'https://source.unsplash.com/1200x800/?black,bean,burger,sweet,potato', 'https://www.nhs.uk/baby/weaning-and-feeding/babys-first-solid-foods/', 'Hamburgueres grandes, moles e sem crosta dura; feijao esmagado; batata-doce macia; sem sal.', 'Separar a massa da bebe antes de temperos fortes e sal.', '1. Assar ou cozer batata-doce ate ficar macia.\n2. Esmagar feijao preto cozido com batata-doce e aveia.\n3. Moldar hamburgueres grandes e achatados.\n4. Cozinhar no forno ate firmarem sem secar.\n5. Separar porcao BLW e verificar que desfaz com pressao dos dedos.\n6. Servir os adultos com arroz e temperos no prato.'),
('RF015', 'Acorda suave de grao e ovo com couve', 'Vegetariana', 'por_testar', 10, 25, 'baixo', 'https://source.unsplash.com/1200x800/?bread,egg,chickpeas,soup', 'https://www.nhs.uk/baby/weaning-and-feeding/babys-first-solid-foods/', 'Textura humida; pao bem demolhado; grao esmagado; ovo completamente cozinhado; sem sal.', 'Retirar a porcao antes de salgar e antes de alho forte para adultos.', '1. Demolhar pao em agua quente sem sal.\n2. Cozer couve ate ficar muito macia.\n3. Juntar grao esmagado e ovo batido, mexendo ate cozinhar totalmente.\n4. Ajustar com agua para ficar humido.\n5. Retirar porcao BLW e arrefecer.\n6. Temperar a dose dos adultos no fim.'),
('RF016', 'Dahl suave de lentilhas vermelhas e espinafres', 'Vegan', 'por_testar', 10, 25, 'baixo', 'https://source.unsplash.com/1200x800/?red,lentil,dahl,spinach', 'https://www.nhs.uk/baby/weaning-and-feeding/babys-first-solid-foods/', 'Lentilhas desfeitas e ricas em ferro; espinafres bem cozidos e picados; arroz humido; sem sal.', 'Separar antes de salgar ou adicionar picante.', '1. Cozer lentilhas vermelhas com cenoura e tomate sem sal.\n2. Juntar espinafres picados e cozinhar bem.\n3. Deixar o dahl espesso mas humido.\n4. Servir com arroz muito macio.\n5. Retirar a porcao BLW e esmagar grumos grandes.\n6. Temperar adultos com especiarias suaves no prato.'),
('RF017', 'Quinoa cremosa com grao, abobora e brocolos', 'Vegan', 'por_testar', 10, 25, 'medio', 'https://source.unsplash.com/1200x800/?quinoa,chickpeas,broccoli', 'https://www.nhs.uk/baby/weaning-and-feeding/babys-first-solid-foods/', 'Quinoa muito bem cozida e humida; grao esmagado; abobora e brocolos macios; sem sal.', 'Separar antes de salgar a panela dos adultos.', '1. Lavar bem a quinoa.\n2. Cozer quinoa com abobora em cubos e bastante agua.\n3. Juntar grao cozido e brocolos no fim.\n4. Cozinhar ate tudo ficar macio e cremoso.\n5. Retirar porcao BLW e esmagar o grao.\n6. Finalizar adultos com azeite e ervas.'),
('RF018', 'Croquetes macios de grao e cenoura com batata assada', 'Vegan', 'por_testar', 20, 30, 'baixo', 'https://source.unsplash.com/1200x800/?chickpea,fritters,carrot,potato', 'https://www.nhs.uk/baby/weaning-and-feeding/babys-first-solid-foods/', 'Croquetes grandes e moles; grao bem esmagado; cenoura cozinhada; batata em palitos macios; sem sal.', 'Separar a massa da bebe antes de sal e especiarias fortes.', '1. Esmagar grao cozido com cenoura ralada cozinhada e farinha de aveia.\n2. Moldar croquetes grandes e achatados.\n3. Assar com pouco azeite ate firmarem.\n4. Assar batata em palitos grossos ate ficar macia.\n5. Retirar a porcao BLW sem sal.\n6. Servir adultos com molho temperado a parte.'),
('RF019', 'Risotto simples de cevadinha com ervilhas e cenoura', 'Vegetariana', 'por_testar', 10, 35, 'baixo', 'https://source.unsplash.com/1200x800/?barley,peas,carrot,risotto', 'https://www.nhs.uk/baby/weaning-and-feeding/babys-first-solid-foods/', 'Cevadinha muito cozida e cremosa; ervilhas esmagadas; cenoura macia; sem sal.', 'Separar antes de salgar ou juntar queijo aos adultos.', '1. Cozer cevadinha lentamente com agua sem sal.\n2. Juntar cenoura em cubos pequenos e ervilhas.\n3. Mexer ate ficar cremoso e muito macio.\n4. Retirar porcao BLW e esmagar ervilhas.\n5. Ajustar textura com agua quente.\n6. Os adultos podem juntar queijo ou sal apenas no prato.'),
('RF020', 'Migas humidas de broa, feijao frade e grelos', 'Vegan', 'por_testar', 15, 25, 'baixo', 'https://source.unsplash.com/1200x800/?cornbread,beans,greens', 'https://www.nhs.uk/baby/weaning-and-feeding/babys-first-solid-foods/', 'Broa bem humedecida; feijao frade esmagado; grelos muito cozidos e picados; sem sal.', 'Retirar antes de salgar e antes de alho forte.', '1. Cozer grelos ate ficarem muito macios e picar bem.\n2. Humedecer broa com agua quente sem sal.\n3. Juntar feijao frade cozido e esmagar parte.\n4. Envolver tudo com azeite ate ficar humido.\n5. Separar porcao BLW.\n6. Temperar os adultos com alho e sal no fim.'),
('RF021', 'Pataniscas de pescada no forno com arroz de legumes', 'Peixe', 'por_testar', 20, 25, 'medio', 'https://source.unsplash.com/1200x800/?fish,cakes,rice,vegetables', 'https://www.nhs.uk/baby/weaning-and-feeding/babys-first-solid-foods/', 'Pescada sem espinhas; pataniscas assadas, moles e grandes; arroz humido; sem sal.', 'Separar massa e arroz da bebe antes de salgar a dose dos adultos.', '1. Cozer pescada e retirar todas as espinhas.\n2. Misturar pescada lascada com ovo, farinha e cenoura ralada cozinhada.\n3. Formar discos grandes e assar no forno.\n4. Fazer arroz de legumes bem humido.\n5. Separar porcao BLW sem sal.\n6. Confirmar que as pataniscas desfazem facilmente.'),
('RF022', 'Jardineira vegetariana de feijao manteiga', 'Vegan', 'por_testar', 15, 35, 'baixo', 'https://source.unsplash.com/1200x800/?butter,beans,potatoes,stew', 'https://www.nhs.uk/baby/weaning-and-feeding/babys-first-solid-foods/', 'Feijao manteiga macio e esmagavel; batata, cenoura e ervilhas bem cozidas; sem sal.', 'Separar antes de salgar ou juntar temperos fortes.', '1. Cozer batata e cenoura em cubos grandes.\n2. Juntar feijao manteiga, ervilhas e tomate sem sal.\n3. Estufar ate o molho ficar espesso.\n4. Retirar porcao BLW e esmagar feijao e ervilhas.\n5. Servir com caldo suficiente para ficar humido.\n6. Temperar adultos no fim.'),
('RF023', 'Creme espesso de ervilhas, batata e ovo', 'Vegetariana', 'por_testar', 10, 25, 'baixo', 'https://source.unsplash.com/1200x800/?pea,soup,egg,potato', 'https://www.nhs.uk/baby/weaning-and-feeding/babys-first-solid-foods/', 'Creme espesso sem sal; ervilhas bem cozidas; ovo completamente cozinhado e em tiras ou picado.', 'Separar antes de salgar a sopa dos adultos.', '1. Cozer batata, ervilhas e cenoura em agua sem sal.\n2. Triturar ate ficar creme espesso.\n3. Cozer ovos ate ficarem totalmente cozinhados.\n4. Retirar porcao BLW e juntar ovo picado ou em tiras macias.\n5. Ajustar textura com agua se necessario.\n6. Temperar adultos no prato.'),
('RF024', 'Salmao no forno com batata-doce e couve-flor', 'Peixe', 'por_testar', 10, 25, 'alto', 'https://source.unsplash.com/1200x800/?salmon,sweet,potato,cauliflower', 'https://www.nhs.uk/baby/weaning-and-feeding/babys-first-solid-foods/', 'Salmao bem cozinhado e sem espinhas; batata-doce e couve-flor muito macias; sem sal.', 'Separar a porcao da bebe antes de salgar ou usar molhos.', '1. Assar batata-doce em palitos grossos e couve-flor em floretes grandes.\n2. Assar salmao simples ate ficar completamente cozinhado.\n3. Verificar espinhas com cuidado.\n4. Retirar porcao BLW sem sal.\n5. Desfiar salmao em lascas grandes e humidas.\n6. Temperar adultos com limao, sal e ervas no prato.'),
('RF025', 'Arroz malandrinho de tomate, feijao branco e espinafres', 'Vegan', 'por_testar', 10, 30, 'baixo', 'https://source.unsplash.com/1200x800/?tomato,rice,white,beans,spinach', 'https://www.nhs.uk/baby/weaning-and-feeding/babys-first-solid-foods/', 'Arroz muito macio; feijao branco esmagado; espinafres bem cozidos e picados; sem sal.', 'Retirar antes de salgar a panela dos adultos.', '1. Cozinhar tomate sem sal com arroz e bastante agua.\n2. Juntar feijao branco cozido e espinafres picados.\n3. Deixar o arroz bem malandrinho.\n4. Esmagar parte do feijao.\n5. Separar porcao BLW sem sal.\n6. Finalizar adultos com azeite e temperos a gosto.')
on conflict (code) do update set
  name = excluded.name,
  category = excluded.category,
  prep_time_min = excluded.prep_time_min,
  cook_time_min = excluded.cook_time_min,
  cost_level = excluded.cost_level,
  image_url = excluded.image_url,
  source_url = excluded.source_url,
  blw_summary = excluded.blw_summary,
  separation_moment = excluded.separation_moment,
  notes = excluded.notes;

insert into family_rules (rule_key, rule_value) values
('family', '2 adultos e 1 bebe de 6 meses em BLW'),
('no_meat', 'Nao usar carne'),
('fish_limit', 'Peixe no maximo 2 refeicoes por semana'),
('dairy', 'Evitar leite e derivados tradicionais; preferir alternativas vegetais adequadas'),
('blw_salt_sugar', 'Nunca adicionar sal ou acucar a preparacao principal da bebe'),
('preferences', 'Evitar cogumelos, cebola, curgete, beringela e tofu visiveis; usar triturado ou removivel')
on conflict (rule_key) do update set rule_value = excluded.rule_value;
